        require(_isApprovedOrOwner(msg.sender, 0), "withdraw:not allowed");

        IERC20(_token).transfer(msg.sender, IERC20(_token).balanceOf(address(this)));

        emit WithdrawERC20(_token, msg.sender);
    }

    receive() external payable {}
}

