pragma solidity 0.8.7;

import {IERC20} from '../../../dependencies/openzeppelin/contracts/IERC20.sol';
import {SafeERC20} from '../../../dependencies/openzeppelin/contracts/SafeERC20.sol';
import {IAToken} from '../../../interfaces/IAToken.sol';
import {IStableDebtToken} from '../../../interfaces/IStableDebtToken.sol';
import {IVariableDebtToken} from '../../../interfaces/IVariableDebtToken.sol';
import {IReserveInterestRateStrategy} from '../../../interfaces/IReserveInterestRateStrategy.sol';
import {ReserveConfiguration} from '../configuration/ReserveConfiguration.sol';
import {MathUtils} from '../math/MathUtils.sol';
import {WadRayMath} from '../math/WadRayMath.sol';
import {PercentageMath} from '../math/PercentageMath.sol';
import {Errors} from '../helpers/Errors.sol';
import {Helpers} from '../helpers/Helpers.sol';
import {DataTypes} from '../types/DataTypes.sol';


library ReserveLogic {
  using WadRayMath for uint256;
  using PercentageMath for uint256;
  using SafeERC20 for IERC20;


  event ReserveDataUpdated(
    address indexed asset,
    uint256 liquidityRate,
    uint256 stableBorrowRate,
    uint256 variableBorrowRate,
    uint256 liquidityIndex,
    uint256 variableBorrowIndex
  );
  using ReserveLogic for DataTypes.ReserveData;
  using ReserveConfiguration for DataTypes.ReserveConfigurationMap;


  function getNormalizedIncome(DataTypes.ReserveData storage reserve)
    internal
    view
    returns (uint256)
  {
    uint40 timestamp = reserve.lastUpdateTimestamp;


    if (timestamp == uint40(block.timestamp)) {

      return reserve.liquidityIndex;
    }

    uint256 cumulated = MathUtils
      .calculateLinearInterest(reserve.currentLiquidityRate, timestamp)
      .rayMul(reserve.liquidityIndex);

    return cumulated;
  }


  function getNormalizedDebt(DataTypes.ReserveData storage reserve)
    internal
    view
    returns (uint256)
  {
    uint40 timestamp = reserve.lastUpdateTimestamp;


    if (timestamp == uint40(block.timestamp)) {

      return reserve.variableBorrowIndex;
    }

    uint256 cumulated = MathUtils
      .calculateCompoundedInterest(reserve.currentVariableBorrowRate, timestamp)
      .rayMul(reserve.variableBorrowIndex);

    return cumulated;
  }


  function updateState(
    DataTypes.ReserveData storage reserve,
    DataTypes.ReserveCache memory reserveCache
  ) internal {
    _updateIndexes(reserve, reserveCache);
    _accrueToTreasury(reserve, reserveCache);
  }


  function cumulateToLiquidityIndex(
    DataTypes.ReserveData storage reserve,
    uint256 totalLiquidity,
    uint256 amount
  ) internal {
    uint256 amountToLiquidityRatio = amount.wadToRay().rayDiv(totalLiquidity.wadToRay());

    uint256 result = amountToLiquidityRatio + WadRayMath.RAY;

    result = result.rayMul(reserve.liquidityIndex);
    reserve.liquidityIndex = Helpers.castUint128(result);
  }


  function init(
    DataTypes.ReserveData storage reserve,
    address aTokenAddress,
    address stableDebtTokenAddress,
    address variableDebtTokenAddress,
    address interestRateStrategyAddress
  ) internal {
    require(reserve.aTokenAddress == address(0), Errors.RL_RESERVE_ALREADY_INITIALIZED);

    reserve.liquidityIndex = uint128(WadRayMath.RAY);
    reserve.variableBorrowIndex = uint128(WadRayMath.RAY);
    reserve.aTokenAddress = aTokenAddress;
    reserve.stableDebtTokenAddress = stableDebtTokenAddress;
    reserve.variableDebtTokenAddress = variableDebtTokenAddress;
    reserve.interestRateStrategyAddress = interestRateStrategyAddress;
  }

  struct UpdateInterestRatesLocalVars {
    uint256 nextLiquidityRate;
    uint256 nextStableRate;
    uint256 nextVariableRate;
    uint256 avgStableRate;
    uint256 totalVariableDebt;
  }


  function updateInterestRates(
    DataTypes.ReserveData storage reserve,
    DataTypes.ReserveCache memory reserveCache,
    address reserveAddress,
    uint256 liquidityAdded,
    uint256 liquidityTaken
  ) internal {
    UpdateInterestRatesLocalVars memory vars;

    vars.totalVariableDebt = reserveCache.nextScaledVariableDebt.rayMul(
      reserveCache.nextVariableBorrowIndex
    );

    (
      vars.nextLiquidityRate,
      vars.nextStableRate,
      vars.nextVariableRate
    ) = IReserveInterestRateStrategy(reserve.interestRateStrategyAddress).calculateInterestRates(
      DataTypes.CalculateInterestRatesParams(
        reserveCache.reserveConfiguration.getUnbackedMintCap() > 0 ? reserve.unbacked : 0,
        liquidityAdded,
        liquidityTaken,
        reserveCache.nextTotalStableDebt,
        vars.totalVariableDebt,
        reserveCache.nextAvgStableBorrowRate,
        reserveCache.reserveFactor,
        reserveAddress,
        reserveCache.aTokenAddress
      )
    );

    reserve.currentLiquidityRate = Helpers.castUint128(vars.nextLiquidityRate);
    reserve.currentStableBorrowRate = Helpers.castUint128(vars.nextStableRate);
    reserve.currentVariableBorrowRate = Helpers.castUint128(vars.nextVariableRate);

    emit ReserveDataUpdated(
      reserveAddress,
      vars.nextLiquidityRate,
      vars.nextStableRate,
      vars.nextVariableRate,
      reserveCache.nextLiquidityIndex,
      reserveCache.nextVariableBorrowIndex
    );
  }

  struct AccrueToTreasuryLocalVars {
    uint256 prevTotalStableDebt;
    uint256 prevTotalVariableDebt;
    uint256 currTotalVariableDebt;
    uint256 avgStableRate;
    uint256 cumulatedStableInterest;
    uint256 totalDebtAccrued;
    uint256 amountToMint;
    uint40 stableSupplyUpdatedTimestamp;
  }


  function _accrueToTreasury(
    DataTypes.ReserveData storage reserve,
    DataTypes.ReserveCache memory reserveCache
  ) internal {
    AccrueToTreasuryLocalVars memory vars;

    if (reserveCache.reserveFactor == 0) {
      return;
    }


    vars.prevTotalVariableDebt = reserveCache.currScaledVariableDebt.rayMul(
      reserveCache.currVariableBorrowIndex
    );


    vars.currTotalVariableDebt = reserveCache.currScaledVariableDebt.rayMul(
      reserveCache.nextVariableBorrowIndex
    );


    vars.cumulatedStableInterest = MathUtils.calculateCompoundedInterest(
      reserveCache.currAvgStableBorrowRate,
      reserveCache.stableDebtLastUpdateTimestamp,
      reserveCache.reserveLastUpdateTimestamp
    );

    vars.prevTotalStableDebt = reserveCache.currPrincipalStableDebt.rayMul(
      vars.cumulatedStableInterest
    );


    vars.totalDebtAccrued =
      vars.currTotalVariableDebt +
      reserveCache.currTotalStableDebt -
      vars.prevTotalVariableDebt -
      vars.prevTotalStableDebt;

    vars.amountToMint = vars.totalDebtAccrued.percentMul(reserveCache.reserveFactor);

    if (vars.amountToMint != 0) {
      reserve.accruedToTreasury =
        reserve.accruedToTreasury +
        Helpers.castUint128((vars.amountToMint.rayDiv(reserveCache.nextLiquidityIndex)));
    }
  }


  function _updateIndexes(
    DataTypes.ReserveData storage reserve,
    DataTypes.ReserveCache memory reserveCache
  ) internal {
    reserveCache.nextLiquidityIndex = reserveCache.currLiquidityIndex;
    reserveCache.nextVariableBorrowIndex = reserveCache.currVariableBorrowIndex;


    if (reserveCache.currLiquidityRate > 0) {
      uint256 cumulatedLiquidityInterest = MathUtils.calculateLinearInterest(
        reserveCache.currLiquidityRate,
        reserveCache.reserveLastUpdateTimestamp
      );
      reserveCache.nextLiquidityIndex = cumulatedLiquidityInterest.rayMul(
        reserveCache.currLiquidityIndex
      );
      reserve.liquidityIndex = Helpers.castUint128(reserveCache.nextLiquidityIndex);



      if (reserveCache.currScaledVariableDebt != 0) {
        uint256 cumulatedVariableBorrowInterest = MathUtils.calculateCompoundedInterest(
          reserveCache.currVariableBorrowRate,
          reserveCache.reserveLastUpdateTimestamp
        );
        reserveCache.nextVariableBorrowIndex = cumulatedVariableBorrowInterest.rayMul(
          reserveCache.currVariableBorrowIndex
        );
        reserve.variableBorrowIndex = Helpers.castUint128(reserveCache.nextVariableBorrowIndex);
      }
    }


    reserve.lastUpdateTimestamp = uint40(block.timestamp);
  }


  function cache(DataTypes.ReserveData storage reserve)
    internal
    view
    returns (DataTypes.ReserveCache memory)
  {
    DataTypes.ReserveCache memory reserveCache;

    reserveCache.reserveConfiguration = reserve.configuration;
    reserveCache.reserveFactor = reserveCache.reserveConfiguration.getReserveFactor();
    reserveCache.currLiquidityIndex = reserve.liquidityIndex;
    reserveCache.currVariableBorrowIndex = reserve.variableBorrowIndex;
    reserveCache.currLiquidityRate = reserve.currentLiquidityRate;
    reserveCache.currVariableBorrowRate = reserve.currentVariableBorrowRate;

    reserveCache.aTokenAddress = reserve.aTokenAddress;
    reserveCache.stableDebtTokenAddress = reserve.stableDebtTokenAddress;
    reserveCache.variableDebtTokenAddress = reserve.variableDebtTokenAddress;

    reserveCache.reserveLastUpdateTimestamp = reserve.lastUpdateTimestamp;

    reserveCache.currScaledVariableDebt = reserveCache.nextScaledVariableDebt = IVariableDebtToken(
      reserveCache.variableDebtTokenAddress
    ).scaledTotalSupply();

    (
      reserveCache.currPrincipalStableDebt,
      reserveCache.currTotalStableDebt,
      reserveCache.currAvgStableBorrowRate,
      reserveCache.stableDebtLastUpdateTimestamp
    ) = IStableDebtToken(reserveCache.stableDebtTokenAddress).getSupplyData();



    reserveCache.nextTotalStableDebt = reserveCache.currTotalStableDebt;
    reserveCache.nextAvgStableBorrowRate = reserveCache.currAvgStableBorrowRate;

    return reserveCache;
  }
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/math/Math.sol";
import "./interfaces/IStaking.sol";


contract Staking is IStaking, Ownable {
  using SafeERC20 for ERC20;
  using SafeMath for uint256;


  ERC20 public immutable token;


  uint256 public duration;


  uint256 private minDelay;


  uint256 private timeUnlock;


  mapping(address => Stake) internal stakes;


  mapping(address => address) public proposedDelegates;



  mapping(address => address) public accountDelegates;


  mapping(address => address) public delegateAccounts;


  mapping(bytes32 => bool) private usedIds;


  mapping(bytes32 => uint256) private unlockTimestamps;


  string public name;
  string public symbol;


  constructor(
    ERC20 _token,
    string memory _name,
    string memory _symbol,
    uint256 _duration,
    uint256 _minDelay
  ) {
    token = _token;
    name = _name;
    symbol = _symbol;
    duration = _duration;
    minDelay = _minDelay;
  }


  function setMetaData(string memory _name, string memory _symbol)
    external
    onlyOwner
  {
    name = _name;
    symbol = _symbol;
  }


  function scheduleDurationChange(uint256 delay) external onlyOwner {
    require(timeUnlock == 0, "TIMELOCK_ACTIVE");
    require(delay >= minDelay, "INVALID_DELAY");
    timeUnlock = block.timestamp + delay;
    emit ScheduleDurationChange(timeUnlock);
  }


  function cancelDurationChange() external onlyOwner {
    require(timeUnlock > 0, "TIMELOCK_INACTIVE");
    delete timeUnlock;
    emit CancelDurationChange();
  }


  function setDuration(uint256 _duration) external onlyOwner {
    require(_duration != 0, "DURATION_INVALID");
    require(timeUnlock > 0, "TIMELOCK_INACTIVE");
    require(block.timestamp >= timeUnlock, "TIMELOCKED");
    duration = _duration;
    delete timeUnlock;
    emit CompleteDurationChange(_duration);
  }


  function proposeDelegate(address delegate) external {
    require(accountDelegates[msg.sender] == address(0), "SENDER_HAS_DELEGATE");
    require(delegateAccounts[delegate] == address(0), "DELEGATE_IS_TAKEN");
    require(stakes[delegate].balance == 0, "DELEGATE_MUST_NOT_BE_STAKED");
    proposedDelegates[msg.sender] = delegate;
    emit ProposeDelegate(delegate, msg.sender);
  }


  function setDelegate(address account) external {
    require(proposedDelegates[account] == msg.sender, "MUST_BE_PROPOSED");
    require(delegateAccounts[msg.sender] == address(0), "DELEGATE_IS_TAKEN");
    require(stakes[msg.sender].balance == 0, "DELEGATE_MUST_NOT_BE_STAKED");
    accountDelegates[account] = msg.sender;
    delegateAccounts[msg.sender] = account;
    delete proposedDelegates[account];
    emit SetDelegate(msg.sender, account);
  }


  function unsetDelegate(address delegate) external {
    require(accountDelegates[msg.sender] == delegate, "DELEGATE_NOT_SET");
    accountDelegates[msg.sender] = address(0);
    delegateAccounts[delegate] = address(0);
  }


  function stake(uint256 amount) external override {
    if (delegateAccounts[msg.sender] != address(0)) {
      _stake(delegateAccounts[msg.sender], amount);
    } else {
      _stake(msg.sender, amount);
    }
  }


  function unstake(uint256 amount) external override {
    address account;
    delegateAccounts[msg.sender] != address(0)
      ? account = delegateAccounts[msg.sender]
      : account = msg.sender;
    _unstake(account, amount);
    token.transfer(account, amount);
    emit Transfer(account, address(0), amount);
  }


  function getStakes(address account)
    external
    view
    override
    returns (Stake memory accountStake)
  {
    return stakes[account];
  }


  function totalSupply() external view override returns (uint256) {
    return token.balanceOf(address(this));
  }


  function balanceOf(address account)
    external
    view
    override
    returns (uint256 total)
  {
    return stakes[account].balance;
  }


  function decimals() external view override returns (uint8) {
    return token.decimals();
  }


  function stakeFor(address account, uint256 amount) public override {
    _stake(account, amount);
  }


  function available(address account) public view override returns (uint256) {
    Stake storage selected = stakes[account];
    uint256 _available = (block.timestamp.sub(selected.timestamp))
      .mul(selected.balance)
      .div(selected.duration);
    if (_available >= stakes[account].balance) {
      return stakes[account].balance;
    } else {
      return _available;
    }
  }


  function _stake(address account, uint256 amount) internal {
    require(amount > 0, "AMOUNT_INVALID");
    stakes[account].duration = duration;
    if (stakes[account].balance == 0) {
      stakes[account].balance = amount;
      stakes[account].timestamp = block.timestamp;
    } else {
      uint256 nowAvailable = available(account);
      stakes[account].balance = stakes[account].balance.add(amount);
      stakes[account].timestamp = block.timestamp.sub(
        nowAvailable.mul(stakes[account].duration).div(stakes[account].balance)
      );
    }
    token.safeTransferFrom(msg.sender, address(this), amount);
    emit Transfer(address(0), account, amount);
  }


  function _unstake(address account, uint256 amount) internal {
    Stake storage selected = stakes[account];
    require(amount <= available(account), "AMOUNT_EXCEEDS_AVAILABLE");
    selected.balance = selected.balance.sub(amount);
  }
}

pragma solidity ^0.7.6;
pragma abicoder v2;

import "@openzeppelin/contracts-upgradeable/proxy/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC721/ERC721Upgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "./IZoanRouter.sol";

contract CryptoZoan is
    Initializable,
    AccessControlUpgradeable,
    ERC721Upgradeable
{
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    enum Tribe {
        SKYLER,
        HYDREIN,
        PLASMER,
        STONIC
    }

    event Migration(uint256 indexed tokenId, address user);
    event LayEgg(uint256 indexed tokenId, address buyer);
    event CreateCollections(
        uint256 indexed tokenId,
        address buyer,
        Tribe tribe,
        uint256 dna,
        uint256 collections
    );
    event Evolve(uint256 indexed tokenId, uint256 dna);
    event UpdateTribe(uint256 indexed tokenId, Tribe tribe);
    event UpgradeGeneration(uint256 indexed tokenId, uint256 newGeneration);
    event Exp(uint256 indexed tokenId, uint256 exp);
    event Working(uint256 indexed tokenId, uint256 time);


    struct Zoan {
        uint256 collections;
        uint256 generation;
        Tribe tribe;
        uint256 exp;
        uint256 dna;
        uint256 bornTime;
    }

    struct ItemSale {
        uint256 tokenId;
        address owner;
        uint256 price;
    }

    mapping(uint256 => uint256) public latestBlockTransfer;

    IZoanRouter public router;
    uint256 public latestTokenId;
    mapping(uint256 => bool) public isEvolved;

    mapping(uint256 => Zoan) internal zoans;

    IERC20 public zoonToken;
    address public dev;
    address public migration;

    bytes32 public constant ZOAN_ADMIN = keccak256("ZOAN_ADMIN");

    function initialize(
        string memory _name,
        string memory _symbol,
        address _router,
        address _zoonToken
    ) public initializer {
        __ERC721_init(_name, _symbol);
        __AccessControl_init_unchained();

        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _setupRole(ZOAN_ADMIN, msg.sender);
        zoonToken = IERC20(_zoonToken);
        dev = msg.sender;

        router = IZoanRouter(_router);
    }

    modifier onlyEvolver() {
        require(router.evolvers(msg.sender), "require Evolver.");
        _;
    }

    modifier onlyMigration() {
        require(msg.sender == migration, "require Migration.");
        _;
    }

    modifier onlyBattlefield() {
        require(router.battlefields(msg.sender), "require Battlefield.");
        _;
    }

    modifier mustEvolved(uint256 _tokenId) {
        require(isEvolved[_tokenId], "require Evolved.");
        _;
    }

    function priceEgg() public view returns (uint256) {
        return router.priceEgg();
    }

    function feeEvolve() public view returns (uint256) {
        return router.feeEvolve();
    }

    function _mint(address to, uint256 tokenId)
        internal
        override(ERC721Upgradeable)
    {
        super._mint(to, tokenId);

        _incrementTokenId();
    }

    function setMigration(address _migration) external {
        require(msg.sender == dev);
        migration = _migration;
    }

    function migrate(
        address _receiver,
        Tribe _tribe,
        uint256 _dna,
        uint256 _exp
    ) public onlyMigration {
        uint256 nextTokenId = _getNextTokenId();
        _mint(_receiver, nextTokenId);

        zoans[nextTokenId] = Zoan({
            collections: 0,
            generation: router.generation(),
            tribe: _tribe,
            exp: _exp,
            dna: _dna,
            bornTime: block.timestamp
        });
        if (_dna > 0) {
            isEvolved[nextTokenId] = true;
        }

        emit Migration(nextTokenId, _receiver);
    }

    function exp(uint256 _tokenId, uint256 _exp) public onlyBattlefield {
        require(_exp > 0, "no exp");

        Zoan storage zoan = zoans[_tokenId];
        zoan.exp = zoan.exp.add(_exp);
        emit Exp(_tokenId, _exp);
    }

    function evolve(
        uint256 _tokenId,
        uint256 _dna,
        uint256 _generation
    ) public onlyEvolver {
        require(
            latestBlockTransfer[_tokenId] < block.number,
            "evolve after transfer"
        );

        Zoan storage zoan = zoans[_tokenId];
        require(!isEvolved[_tokenId], "require: not evolved");

        zoan.bornTime = block.timestamp;
        zoan.dna = _dna;
        zoan.generation = _generation;

        isEvolved[_tokenId] = true;

        emit Evolve(_tokenId, _dna);
    }

    function changeTribe(uint256 _tokenId, Tribe tribe) external onlyEvolver {
        Zoan storage zoan = zoans[_tokenId];
        zoan.tribe = tribe;

        emit UpdateTribe(_tokenId, tribe);
    }

    function upgradeGeneration(uint256 _tokenId, uint256 _generation)
        external
        onlyEvolver
    {
        Zoan storage zoan = zoans[_tokenId];
        zoan.generation = _generation;

        emit UpgradeGeneration(_tokenId, _generation);
    }

    function layEgg(
        address receiver,
        Tribe[] memory tribes,
        uint256 _collections
    ) external onlyEvolver {
        uint256 amount = tribes.length;
        require(amount > 0, "require: >0");
        if (amount == 1) _layEgg(receiver, tribes[0], _collections);
        else
            for (uint256 index = 0; index < amount; index++) {
                _layEgg(receiver, tribes[index], _collections);
            }
    }

    function _layEgg(
        address receiver,
        Tribe tribe,
        uint256 _collections
    ) internal {
        uint256 nextTokenId = _getNextTokenId();
        _mint(receiver, nextTokenId);

        zoans[nextTokenId] = Zoan({
            collections: _collections,
            generation: router.generation(),
            tribe: tribe,
            exp: 0,
            dna: 0,
            bornTime: block.timestamp
        });

        emit LayEgg(nextTokenId, receiver);
    }

    function createCollections(
        address receiver,
        Tribe tribe,
        uint256 _collections,
        uint256 _dna
    ) public onlyEvolver {
        uint256 nextTokenId = _getNextTokenId();
        _mint(receiver, nextTokenId);

        zoans[nextTokenId] = Zoan({
            collections: _collections,
            generation: router.generation(),
            tribe: tribe,
            exp: 0,
            dna: _dna,
            bornTime: block.timestamp
        });
        isEvolved[nextTokenId] = true;

        emit CreateCollections(
            nextTokenId,
            receiver,
            tribe,
            _dna,
            _collections
        );
    }


    function _getNextTokenId() private view returns (uint256) {
        return latestTokenId.add(1);
    }


    function _incrementTokenId() private {
        latestTokenId++;
    }

    function getZoan(uint256 _tokenId) public view returns (Zoan memory) {
        return zoans[_tokenId];
    }

    function isApprovedForAll(address owner, address operator)
        public
        view
        virtual
        override
        returns (bool)
    {
        if (router.markets(operator)) return true;
        return super.isApprovedForAll(owner, operator);
    }

    function _transfer(
        address from,
        address to,
        uint256 tokenId
    ) internal virtual override {
        if (
            router.usersLock(to) ||
            router.usersLock(from) ||
            router.tokensLock(tokenId)
        ) {
            revert("locked.");
        }

        latestBlockTransfer[tokenId] = block.number;
        return super._transfer(from, to, tokenId);
    }

    function recoverZoon(uint256 amount) public {
        require(msg.sender == dev);
        zoonToken.transfer(msg.sender, amount); 
    }
}

pragma solidity 0.8.10;
import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./IMarket.sol";
import "./OwnableContract.sol";
import "./IBaseDoNFT.sol";

contract Market is OwnableContract,ReentrancyGuard,IMarket{
    uint64 constant private E5 = 1e5;
    uint64 constant private SECONDS_IN_DAY = 86400;
    mapping(address=>Credit) internal creditMap;
    mapping(address=>Royalty) internal royaltyMap;
    uint256 public fee;
    uint256 public balanceOfFee;
    address payable public beneficiary;
    string private _name;

    constructor(string memory name_){
        _name = name_;
    }

    modifier onlyApprovedOrOwner(address spender,address nftAddress,uint256 tokenId) {
        address owner = ERC721(nftAddress).ownerOf(tokenId);
        require(owner != address(0),"ERC721: operator query for nonexistent token");
        require(spender == owner || ERC721(nftAddress).getApproved(tokenId) == spender || ERC721(nftAddress).isApprovedForAll(owner, spender));
        _;
    }
    function getName()public view returns(string memory){
        return _name;
    }

    function mintWNftAndOnLent (
        address doNftAddress,
        uint256 oNftId,
        uint64 maxEndTime,
        uint64 minDuration,
        uint256 pricePerSecond
    ) public nonReentrant onlyApprovedOrOwner(msg.sender,IBaseDoNFT(doNftAddress).getOrignalNftAddress(),oNftId){
        uint256 nftId = IBaseDoNFT(doNftAddress).mintWNft(oNftId);
        onLent(doNftAddress, nftId, maxEndTime,minDuration, pricePerSecond);
    }

    function onLent(
        address nftAddress,
        uint256 nftId,
        uint64 maxEndTime,
        uint64 minDuration,
        uint256 pricePerSecond
    ) public onlyApprovedOrOwner(msg.sender,nftAddress,nftId){
        require(IERC165(nftAddress).supportsInterface(type(IBaseDoNFT).interfaceId),"not doNFT");
        address owner = ERC721(nftAddress).ownerOf(nftId);
        Lending storage lending = creditMap[nftAddress].lendingMap[nftId];
        lending.lender = owner;
        lending.nftAddress = nftAddress;
        lending.nftId = nftId;
        lending.maxEndTime = maxEndTime;
        lending.minDuration = minDuration;
        lending.pricePerSecond = pricePerSecond;
        lending.nonce = IBaseDoNFT(nftAddress).getNonce(nftId);
        emit OnLent(owner,nftAddress, nftId, maxEndTime,minDuration,pricePerSecond);
    }

    function offLent(address nftAddress, uint256 nftId) public onlyApprovedOrOwner(msg.sender,nftAddress,nftId){
        delete creditMap[nftAddress].lendingMap[nftId];
        emit OffLent(msg.sender,nftAddress, nftId);
    }

    function getLent(address nftAddress,uint256 nftId) public view returns (Lending memory lenting){
        lenting = creditMap[nftAddress].lendingMap[nftId];
    }


    function makeDeal(address nftAddress,uint256 tokenId,uint256 durationId,uint64 startTime,uint64 endTime) public nonReentrant payable virtual returns(uint256 tid){
        Lending storage lending = creditMap[nftAddress].lendingMap[tokenId];
        require(isOnLent(nftAddress,tokenId),"not on lend");
        require(endTime <= lending.maxEndTime,"endTime > lending.maxEndTime ");
        (uint64 dStart,uint64 dEnd) = IBaseDoNFT(nftAddress).getDuration(durationId);
        if(!(startTime == block.timestamp && endTime== dEnd)){
            require((endTime-startTime) >= lending.minDuration,"duration < minDuration");
        }
        distributePayment(nftAddress, tokenId, startTime, endTime);
        tid = IBaseDoNFT(nftAddress).mint(tokenId, durationId, startTime, endTime, msg.sender);
        emit MakeDeal(msg.sender, lending.lender, lending.nftAddress, lending.nftId, startTime, endTime, lending.pricePerSecond,tid);
    }

    function makeDealNow(address nftAddress,uint256 tokenId,uint256 durationId,uint64 duration) public payable virtual returns(uint256 tid){
        tid = makeDeal(nftAddress, tokenId, durationId, uint64(block.timestamp), uint64(block.timestamp + duration));
    }

    function distributePayment(address nftAddress,uint256 nftId,uint64 startTime,uint64 endTime) internal returns (uint256 totolPrice,uint256 leftTotolPrice,uint256 curFee,uint256 curRoyalty){
        Lending storage lending = creditMap[nftAddress].lendingMap[nftId];
        totolPrice = lending.pricePerSecond * (endTime - startTime);
        curFee = totolPrice * fee / E5;
        curRoyalty = totolPrice * royaltyMap[nftAddress].fee / E5;
        royaltyMap[nftAddress].balance += curRoyalty;
        balanceOfFee += curFee;
        leftTotolPrice = totolPrice - curFee - curRoyalty;
        require(msg.value >= totolPrice);
        payable(ERC721(nftAddress).ownerOf(nftId)).transfer(leftTotolPrice);

        if (msg.value > totolPrice) {
           payable(msg.sender).transfer(msg.value - totolPrice);
        }
    }

    function setFee(uint256 fee_) public onlyAdmin{
        fee = fee_;
    }

    function setMarketBeneficiary(address payable beneficiary_) public onlyAdmin{
        beneficiary = beneficiary_;
    }

    function claimFee() public{
        require(msg.sender==beneficiary,"not beneficiary");
        beneficiary.transfer(balanceOfFee);
        balanceOfFee = 0;
    }

    function setRoyalty(address nftAddress,uint256 fee_) public onlyAdmin{
        royaltyMap[nftAddress].fee = fee_;
    }

    function setRoyaltyBeneficiary(address nftAddress,address payable beneficiary_) public onlyAdmin{
        royaltyMap[nftAddress].beneficiary = beneficiary_;
    }

    function claimRoyalty(address nftAddress) public{
        royaltyMap[nftAddress].beneficiary.transfer(royaltyMap[nftAddress].balance);
        royaltyMap[nftAddress].balance = 0;
    }

    function isOnLent(address nftAddress,uint256 nftId) public view returns (bool){
        Lending storage lending = creditMap[nftAddress].lendingMap[nftId];
        return  lending.nftId > 0 && 
                lending.maxEndTime > block.timestamp && 
                lending.nonce == IBaseDoNFT(nftAddress).getNonce(nftId);
    }

}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";


contract FixedFeeSwap is ERC20, Ownable {
    using SafeERC20 for IERC20;

    IERC20 immutable public token0;
    IERC20 immutable public token1;
    uint256 immutable public amountMultiplier;

    uint8 immutable private _decimals;


    uint256 constant private _DIRECTION_MASK = 1 << 255;
    uint256 constant private _AMOUNT_MASK = ~_DIRECTION_MASK;
    uint256 constant private _FEE_SCALE = 1e18;

    constructor(
        IERC20 _token0,
        IERC20 _token1,
        uint256 _fee,
        string memory name,
        string memory symbol,
        uint8 decimals_
    )
        ERC20(name, symbol)
    {
        require(_fee < _FEE_SCALE, "Fee should be < 1");
        require(_fee > 0, "Fee should be > 0");

        amountMultiplier = _FEE_SCALE - _fee;
        token0 = _token0;
        token1 = _token1;
        _decimals = decimals_;
    }

    function decimals() public view virtual override returns(uint8) {
        return _decimals;
    }

    function getReturn(uint256 inputAmount) public view returns(uint256 outputAmount) {
        outputAmount = inputAmount * amountMultiplier / _FEE_SCALE;
    }

    function deposit(uint256 token0Amount, uint256 token1Amount) external returns(uint256 share) {
        share = depositFor(token0Amount, token1Amount, msg.sender);
    }

    function depositFor(uint256 token0Amount, uint256 token1Amount, address to) public onlyOwner returns(uint256 share) {
        uint256 inputAmount = token0Amount + token1Amount;
        require(inputAmount > 0, "Empty deposit is not allowed");

        uint256 _totalSupply = totalSupply();
        share = inputAmount;
        if (_totalSupply > 0) {
            uint256 totalBalance = token0.balanceOf(address(this)) + token1.balanceOf(address(this));
            share = inputAmount * _totalSupply / totalBalance;
        }

        if (token0Amount > 0) {
            token0.safeTransferFrom(msg.sender, address(this), token0Amount);
        }
        if (token1Amount > 0) {
            token1.safeTransferFrom(msg.sender, address(this), token1Amount);
        }
        _mint(to, share);
    }

    function withdraw(uint256 amount) external returns(uint256 token0Share, uint256 token1Share) {
        (token0Share, token1Share) = withdrawFor(amount, msg.sender);
    }

    function withdrawFor(uint256 amount, address to) public returns(uint256 token0Share, uint256 token1Share) {
        require(amount > 0, "Empty withdrawal is not allowed");

        uint256 _totalSupply = totalSupply();
        token0Share = token0.balanceOf(address(this)) * amount / _totalSupply;
        token1Share = token1.balanceOf(address(this)) * amount / _totalSupply;

        _burn(msg.sender, amount);
        if (token0Share > 0) {
            token0.safeTransfer(to, token0Share);
        }
        if (token1Share > 0) {
            token1.safeTransfer(to, token1Share);
        }
    }

    function swap0To1(uint256 inputAmount) external returns(uint256 outputAmount) {
        outputAmount = swap0To1For(inputAmount, msg.sender);
    }

    function swap1To0(uint256 inputAmount) external returns(uint256 outputAmount) {
        outputAmount = swap1To0For(inputAmount, msg.sender);
    }

    function swap0To1For(uint256 inputAmount, address to) public returns(uint256 outputAmount) {
        return _swap(token0, token1, inputAmount, to);
    }

    function swap1To0For(uint256 inputAmount, address to) public returns(uint256 outputAmount) {
        return _swap(token1, token0, inputAmount, to);
    }

    function _swap(IERC20 tokenFrom, IERC20 tokenTo, uint256 inputAmount, address to) private returns(uint256 outputAmount) {
        outputAmount = getReturn(inputAmount);
        require(outputAmount > 0, "Empty swap is not allowed");
        tokenFrom.safeTransferFrom(msg.sender, address(this), inputAmount);
        tokenTo.safeTransfer(to, outputAmount);
    }
}

